package cmd

import (
	"encoding/json"
	"fmt"
	"text/tabwriter"

	"github.com/kdobmayer/kond-test-go-cli/pipeline"
	"github.com/spf13/cobra"
	"gopkg.in/yaml.v3"
)

var validateCmd = &cobra.Command{
	Use:   "validate [pipeline-file]",
	Short: "Validate a pipeline YAML file",
	Long:  `Check a pipeline definition for errors without executing it.`,
	Args:  cobra.ExactArgs(1),
	RunE:  runValidate,
}

func init() {
	rootCmd.AddCommand(validateCmd)
	validateCmd.Flags().Bool("strict", false, "Enable strict validation (check for best practices)")
}

func runValidate(cmd *cobra.Command, args []string) error {
	pipelineFile := args[0]
	strict, _ := cmd.Flags().GetBool("strict")

	p, err := pipeline.LoadPipeline(pipelineFile)
	if err != nil {
		return fmt.Errorf("loading pipeline: %w", err)
	}

	errs := p.Validate()

	// Strict mode adds additional checks
	if strict {
		strictErrs := validateStrict(p)
		errs = append(errs, strictErrs...)
	}

	if len(errs) == 0 {
		fmt.Fprintf(cmd.OutOrStdout(), "Pipeline %q is valid.\n", p.Name)
		return nil
	}

	return renderValidationErrors(cmd, errs)
}

// validateStrict performs additional best-practice checks
func validateStrict(p *pipeline.Pipeline) []pipeline.ValidationError {
	var errs []pipeline.ValidationError

	for i, step := range p.Steps {
		// Check for missing timeout
		if step.Timeout == "" {
			errs = append(errs, pipeline.ValidationError{
				Field:   fmt.Sprintf("steps[%d].timeout", i),
				Message: fmt.Sprintf("step %q has no timeout configured", step.Name),
			})
		}

		// Check for missing description (workdir as proxy for organization)
		if step.WorkDir == "" && len(p.Steps) > 5 {
			errs = append(errs, pipeline.ValidationError{
				Field:   fmt.Sprintf("steps[%d].workdir", i),
				Message: fmt.Sprintf("step %q has no workdir (recommended for large pipelines)", step.Name),
			})
		}
	}

	// Check for pipeline-level env
	if len(p.Env) == 0 {
		errs = append(errs, pipeline.ValidationError{
			Field:   "env",
			Message: "no pipeline-level environment variables defined",
		})
	}

	return errs
}

func renderValidationErrors(cmd *cobra.Command, errs []pipeline.ValidationError) error {
	// NOTE: duplicated output formatting (intentional rough edge)
	switch outputFormat {
	case "json":
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(errs)
	case "yaml":
		enc := yaml.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent(2)
		defer enc.Close()
		return enc.Encode(errs)
	default:
		w := tabwriter.NewWriter(cmd.OutOrStdout(), 0, 0, 2, ' ', 0)
		fmt.Fprintln(w, "FIELD\tMESSAGE")
		fmt.Fprintln(w, "-----\t-------")
		for _, e := range errs {
			fmt.Fprintf(w, "%s\t%s\n", e.Field, e.Message)
		}
		if err := w.Flush(); err != nil {
			return err
		}
	}

	return fmt.Errorf("pipeline has %d validation error(s)", len(errs))
}

package cmd

import (
	"bytes"
	"os"
	"path/filepath"
	"testing"
)

func TestInitCommand(t *testing.T) {
	dir := t.TempDir()

	rootCmd.SetArgs([]string{"init", "test-pipeline", "-d", dir})
	var buf bytes.Buffer
	rootCmd.SetOut(&buf)

	if err := rootCmd.Execute(); err != nil {
		t.Fatalf("init command error = %v", err)
	}

	// Verify file was created
	path := filepath.Join(dir, "test-pipeline.yaml")
	if _, err := os.Stat(path); err != nil {
		t.Errorf("pipeline file not created: %v", err)
	}
}

func TestInitCommand_AlreadyExists(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "existing.yaml")
	os.WriteFile(path, []byte("name: existing"), 0644)

	rootCmd.SetArgs([]string{"init", "existing", "-d", dir})
	var buf bytes.Buffer
	rootCmd.SetOut(&buf)
	rootCmd.SetErr(&buf)

	err := rootCmd.Execute()
	if err == nil {
		t.Error("expected error when file already exists")
	}
}

func TestInitCommand_CustomSteps(t *testing.T) {
	dir := t.TempDir()

	rootCmd.SetArgs([]string{"init", "multi", "-d", dir, "--steps", "4"})
	var buf bytes.Buffer
	rootCmd.SetOut(&buf)

	if err := rootCmd.Execute(); err != nil {
		t.Fatalf("init command error = %v", err)
	}

	// Read and verify step count
	data, _ := os.ReadFile(filepath.Join(dir, "multi.yaml"))
	content := string(data)
	// Should have step-4
	if !bytes.Contains([]byte(content), []byte("step-4")) {
		t.Error("expected step-4 in pipeline")
	}
}

func TestValidateCommand_Valid(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "valid.yaml")
	os.WriteFile(path, []byte(`
name: valid
steps:
  - name: a
    command: echo a
`), 0644)

	rootCmd.SetArgs([]string{"validate", path})
	var buf bytes.Buffer
	rootCmd.SetOut(&buf)

	if err := rootCmd.Execute(); err != nil {
		t.Fatalf("validate command error = %v", err)
	}

	if !bytes.Contains(buf.Bytes(), []byte("valid")) {
		t.Error("expected 'valid' in output")
	}
}

func TestValidateCommand_Invalid(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "invalid.yaml")
	os.WriteFile(path, []byte(`
name: ""
steps: []
`), 0644)

	rootCmd.SetArgs([]string{"validate", path})
	var buf bytes.Buffer
	rootCmd.SetOut(&buf)
	rootCmd.SetErr(&buf)

	err := rootCmd.Execute()
	if err == nil {
		t.Error("expected error for invalid pipeline")
	}
}

func TestRunCommand_DryRun(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "pipeline.yaml")
	os.WriteFile(path, []byte(`
name: dry-run-test
steps:
  - name: a
    command: echo hello
  - name: b
    command: echo world
    depends_on: [a]
`), 0644)

	rootCmd.SetArgs([]string{"run", path, "--dry-run"})
	var buf bytes.Buffer
	rootCmd.SetOut(&buf)

	if err := rootCmd.Execute(); err != nil {
		t.Fatalf("run --dry-run error = %v", err)
	}

	out := buf.String()
	if !bytes.Contains([]byte(out), []byte("Level")) {
		t.Error("expected execution plan output")
	}
}

func TestGenerateTemplateSteps(t *testing.T) {
	steps := generateTemplateSteps(3)
	if len(steps) != 3 {
		t.Fatalf("expected 3 steps, got %d", len(steps))
	}
	if steps[0].Name != "step-1" {
		t.Errorf("first step name = %q, want %q", steps[0].Name, "step-1")
	}
	if len(steps[0].DependsOn) != 0 {
		t.Error("first step should have no dependencies")
	}
	if len(steps[2].DependsOn) != 1 || steps[2].DependsOn[0] != "step-2" {
		t.Error("step-3 should depend on step-2")
	}
}

